import{_ as a,c as n,a as e,o as t}from"./app-CddT6UHG.js";const l={};function i(o,s){return t(),n("div",null,s[0]||(s[0]=[e(`<h1 id="dirty-streams" tabindex="-1"><a class="header-anchor" href="#dirty-streams"><span>Dirty Streams</span></a></h1><p>Dirty Streams automatically publish entity change events to Redis Streams whenever entities are inserted, updated, or deleted. This enables cross-service event-driven architectures built on the existing <a href="/guide/event_broker">Event Broker</a>.</p><h2 id="tag-syntax" tabindex="-1"><a class="header-anchor" href="#tag-syntax"><span>Tag Syntax</span></a></h2><p>Dirty streams are configured with an entity-level tag on the <code>ID</code> field:</p><div class="language-text line-numbers-mode" data-highlighter="prismjs" data-ext="text"><pre><code class="language-text"><span class="line">dirtyStream=&lt;Name&gt;/&lt;redisPool&gt;/&lt;ops&gt;</span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><table><thead><tr><th style="text-align:left;">Part</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>&lt;Name&gt;</code></td><td style="text-align:left;">Stream name</td></tr><tr><td style="text-align:left;"><code>&lt;redisPool&gt;</code></td><td style="text-align:left;">Redis pool code. Leave empty to use the entity&#39;s default Redis pool.</td></tr><tr><td style="text-align:left;"><code>&lt;ops&gt;</code></td><td style="text-align:left;">Combination of <code>I</code> (insert), <code>U</code> (update), <code>D</code> (delete). Defaults to <code>IUD</code> if omitted.</td></tr></tbody></table><p>Multiple streams are separated by commas:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">ID <span class="token builtin">uint64</span> <span class="token string">\`orm:&quot;dirtyStream=UserStream,AuditStream//I&quot;\`</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="shorthand-examples" tabindex="-1"><a class="header-anchor" href="#shorthand-examples"><span>Shorthand Examples</span></a></h3><ul><li><code>dirtyStream=MyStream</code> -- all ops (<code>IUD</code>), default pool</li><li><code>dirtyStream=MyStream//ID</code> -- insert + delete, default pool</li><li><code>dirtyStream=MyStream/cache1/U</code> -- update only, pool <code>cache1</code></li></ul><h2 id="field-level-triggers" tabindex="-1"><a class="header-anchor" href="#field-level-triggers"><span>Field-Level Triggers</span></a></h2><p>Individual fields can specify which streams they trigger on UPDATE:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">Status <span class="token builtin">string</span> <span class="token string">\`orm:&quot;required;enum=active,banned;dirtyStream=UserStatusStream&quot;\`</span></span>
<span class="line">Age    <span class="token builtin">uint32</span> <span class="token string">\`orm:&quot;dirtyStream=UserStatusStream,AuditStream&quot;\`</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div><p>When a field tagged with <code>dirtyStream</code> changes during an UPDATE, the listed streams will publish an event -- even if those streams do not have <code>U</code> in their entity-level ops.</p><div class="hint-container warning"><p class="hint-container-title">Warning</p><p>The stream must be declared on the <code>ID</code> field first. Field-level tags reference streams by name only.</p></div><h2 id="decision-logic" tabindex="-1"><a class="header-anchor" href="#decision-logic"><span>Decision Logic</span></a></h2><p>The following table summarizes when each stream publishes an event:</p><table><thead><tr><th style="text-align:left;">Operation</th><th style="text-align:left;">Publishes when...</th></tr></thead><tbody><tr><td style="text-align:left;">INSERT</td><td style="text-align:left;">Stream has <code>I</code> in ops</td></tr><tr><td style="text-align:left;">DELETE</td><td style="text-align:left;">Stream has <code>D</code> in ops</td></tr><tr><td style="text-align:left;">UPDATE</td><td style="text-align:left;">Stream has <code>U</code> in ops (always publishes), OR any field tagged with this stream changed</td></tr></tbody></table><h2 id="full-example" tabindex="-1"><a class="header-anchor" href="#full-example"><span>Full Example</span></a></h2><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> UserEntity <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    ID     <span class="token builtin">uint64</span> <span class="token string">\`orm:&quot;dirtyStream=UserStream,UserStatusStream//ID&quot;\`</span></span>
<span class="line">    Name   <span class="token builtin">string</span> <span class="token string">\`orm:&quot;required&quot;\`</span></span>
<span class="line">    Status <span class="token builtin">string</span> <span class="token string">\`orm:&quot;required;enum=active,banned;dirtyStream=UserStatusStream&quot;\`</span></span>
<span class="line">    Age    <span class="token builtin">uint8</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><ul><li><strong>UserStream</strong> -- publishes on INSERT, UPDATE, and DELETE (default <code>IUD</code> ops).</li><li><strong>UserStatusStream</strong> -- publishes on INSERT and DELETE (from the <code>ID</code> ops), plus UPDATE only when <code>Status</code> changes (from the field-level tag).</li></ul><h2 id="stream-registration" tabindex="-1"><a class="header-anchor" href="#stream-registration"><span>Stream Registration</span></a></h2><p>Dirty streams are automatically registered with the Event Broker during <code>registry.Validate()</code>. No manual <code>RegisterRedisStream()</code> call is needed.</p><h2 id="event-payload" tabindex="-1"><a class="header-anchor" href="#event-payload"><span>Event Payload</span></a></h2><p>Each dirty stream event is serialized using msgpack with the following structure:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">type</span> DirtyStreamEvent <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    EntityType <span class="token builtin">string</span>                      <span class="token string">\`msgpack:&quot;et&quot;\`</span>           <span class="token comment">// table name</span></span>
<span class="line">    EntityID   <span class="token builtin">uint64</span>                      <span class="token string">\`msgpack:&quot;id&quot;\`</span></span>
<span class="line">    FlushType  <span class="token builtin">uint8</span>                       <span class="token string">\`msgpack:&quot;ft&quot;\`</span>           <span class="token comment">// 1=insert, 2=update, 3=delete</span></span>
<span class="line">    Changes    <span class="token keyword">map</span><span class="token punctuation">[</span><span class="token builtin">string</span><span class="token punctuation">]</span>DirtyFieldChange <span class="token string">\`msgpack:&quot;ch,omitempty&quot;\`</span> <span class="token comment">// field -&gt; old+new (update only)</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span>
<span class="line"><span class="token keyword">type</span> DirtyFieldChange <span class="token keyword">struct</span> <span class="token punctuation">{</span></span>
<span class="line">    Old AsyncSQLParam <span class="token string">\`msgpack:&quot;o&quot;\`</span></span>
<span class="line">    New AsyncSQLParam <span class="token string">\`msgpack:&quot;n&quot;\`</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="flushtype-constants" tabindex="-1"><a class="header-anchor" href="#flushtype-constants"><span>FlushType Constants</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token keyword">const</span> <span class="token punctuation">(</span></span>
<span class="line">    DirtyStreamInsert <span class="token builtin">uint8</span> <span class="token operator">=</span> <span class="token number">1</span>  <span class="token comment">// fluxaorm.DirtyStreamInsert</span></span>
<span class="line">    DirtyStreamUpdate <span class="token builtin">uint8</span> <span class="token operator">=</span> <span class="token number">2</span>  <span class="token comment">// fluxaorm.DirtyStreamUpdate</span></span>
<span class="line">    DirtyStreamDelete <span class="token builtin">uint8</span> <span class="token operator">=</span> <span class="token number">3</span>  <span class="token comment">// fluxaorm.DirtyStreamDelete</span></span>
<span class="line"><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="dirtyfieldchange-helpers" tabindex="-1"><a class="header-anchor" href="#dirtyfieldchange-helpers"><span>DirtyFieldChange Helpers</span></a></h3><p><code>DirtyFieldChange</code> provides two helper methods for extracting typed values:</p><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>OldValue() any</code></td><td style="text-align:left;">Returns the old value as a Go type</td></tr><tr><td style="text-align:left;"><code>NewValue() any</code></td><td style="text-align:left;">Returns the new value as a Go type</td></tr></tbody></table><h2 id="consuming-events" tabindex="-1"><a class="header-anchor" href="#consuming-events"><span>Consuming Events</span></a></h2><p>Code generation creates a <code>DirtyStreams</code> variable with typed helpers for each stream:</p><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line"><span class="token comment">// Generated code</span></span>
<span class="line"><span class="token keyword">var</span> DirtyStreams <span class="token operator">=</span> dirtyStreamConsumers<span class="token punctuation">{</span></span>
<span class="line">    UserStream<span class="token punctuation">:</span>       dirtyStreamHelper<span class="token punctuation">{</span>streamName<span class="token punctuation">:</span> <span class="token string">&quot;UserStream&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line">    UserStatusStream<span class="token punctuation">:</span> dirtyStreamHelper<span class="token punctuation">{</span>streamName<span class="token punctuation">:</span> <span class="token string">&quot;UserStatusStream&quot;</span><span class="token punctuation">}</span><span class="token punctuation">,</span></span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>Each helper provides:</p><table><thead><tr><th style="text-align:left;">Method</th><th style="text-align:left;">Description</th></tr></thead><tbody><tr><td style="text-align:left;"><code>ConsumeSingle(ctx) (EventsConsumer, error)</code></td><td style="text-align:left;">Creates a single-instance consumer</td></tr><tr><td style="text-align:left;"><code>ConsumeMany(ctx) (EventsConsumer, error)</code></td><td style="text-align:left;">Creates a multi-instance consumer</td></tr><tr><td style="text-align:left;"><code>Name() string</code></td><td style="text-align:left;">Returns the stream name</td></tr></tbody></table><h3 id="example-consumer" tabindex="-1"><a class="header-anchor" href="#example-consumer"><span>Example Consumer</span></a></h3><div class="language-go line-numbers-mode" data-highlighter="prismjs" data-ext="go"><pre><code class="language-go"><span class="line">consumer<span class="token punctuation">,</span> err <span class="token operator">:=</span> entities<span class="token punctuation">.</span>DirtyStreams<span class="token punctuation">.</span>UserStatusStream<span class="token punctuation">.</span><span class="token function">ConsumeSingle</span><span class="token punctuation">(</span>ctx<span class="token punctuation">)</span></span>
<span class="line"><span class="token keyword">if</span> err <span class="token operator">!=</span> <span class="token boolean">nil</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">return</span> err</span>
<span class="line"><span class="token punctuation">}</span></span>
<span class="line">err <span class="token operator">=</span> consumer<span class="token punctuation">.</span><span class="token function">Consume</span><span class="token punctuation">(</span><span class="token number">100</span><span class="token punctuation">,</span> <span class="token number">5</span><span class="token operator">*</span>time<span class="token punctuation">.</span>Second<span class="token punctuation">,</span> <span class="token keyword">func</span><span class="token punctuation">(</span>events <span class="token punctuation">[</span><span class="token punctuation">]</span>fluxaorm<span class="token punctuation">.</span>Event<span class="token punctuation">)</span> <span class="token builtin">error</span> <span class="token punctuation">{</span></span>
<span class="line">    <span class="token keyword">for</span> <span class="token boolean">_</span><span class="token punctuation">,</span> ev <span class="token operator">:=</span> <span class="token keyword">range</span> events <span class="token punctuation">{</span></span>
<span class="line">        <span class="token keyword">var</span> dirty fluxaorm<span class="token punctuation">.</span>DirtyStreamEvent</span>
<span class="line">        ev<span class="token punctuation">.</span><span class="token function">Unserialize</span><span class="token punctuation">(</span><span class="token operator">&amp;</span>dirty<span class="token punctuation">)</span></span>
<span class="line">        fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>dirty<span class="token punctuation">.</span>EntityType<span class="token punctuation">,</span> dirty<span class="token punctuation">.</span>EntityID<span class="token punctuation">,</span> dirty<span class="token punctuation">.</span>FlushType<span class="token punctuation">)</span></span>
<span class="line">        <span class="token keyword">for</span> field<span class="token punctuation">,</span> change <span class="token operator">:=</span> <span class="token keyword">range</span> dirty<span class="token punctuation">.</span>Changes <span class="token punctuation">{</span></span>
<span class="line">            fmt<span class="token punctuation">.</span><span class="token function">Println</span><span class="token punctuation">(</span>field<span class="token punctuation">,</span> change<span class="token punctuation">.</span><span class="token function">OldValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">,</span> <span class="token string">&quot;-&gt;&quot;</span><span class="token punctuation">,</span> change<span class="token punctuation">.</span><span class="token function">NewValue</span><span class="token punctuation">(</span><span class="token punctuation">)</span><span class="token punctuation">)</span></span>
<span class="line">        <span class="token punctuation">}</span></span>
<span class="line">    <span class="token punctuation">}</span></span>
<span class="line">    <span class="token keyword">return</span> <span class="token boolean">nil</span></span>
<span class="line"><span class="token punctuation">}</span><span class="token punctuation">)</span></span>
<span class="line"></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p>For more details on consumer behavior, acknowledgment, and auto-claiming, see the <a href="/guide/event_broker">Event Broker</a> documentation.</p><h2 id="async-flush-support" tabindex="-1"><a class="header-anchor" href="#async-flush-support"><span>Async Flush Support</span></a></h2><p>Dirty streams work with both <code>Flush()</code> (synchronous) and <code>FlushAsync()</code>. When using <code>FlushAsync()</code>, dirty stream events are serialized into the async SQL operation and published by the consumer after SQL execution succeeds. See <a href="/guide/async_flush">Async Flush</a> for more details on async processing.</p>`,41)]))}const c=a(l,[["render",i]]),r=JSON.parse('{"path":"/guide/dirty_streams.html","title":"Dirty Streams","lang":"en-US","frontmatter":{},"git":{"updatedTime":1772370079000,"contributors":[{"name":"lukaszlato","username":"lukaszlato","email":"latolukasz@gmail.com","commits":5,"url":"https://github.com/lukaszlato"},{"name":"Lukasz Lato","username":"","email":"latolukasz@gmail.com","commits":2},{"name":"Claude Opus 4.6","username":"","email":"noreply@anthropic.com","commits":1}],"changelog":[{"hash":"68c07c034c76c3f474552e9ae3c921b0f490e8d6","time":1772370079000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"Remove dirty streams documentation","coAuthors":[{"name":"Claude Opus 4.6","email":"noreply@anthropic.com"}]},{"hash":"456e3bba4fa5c1476f9974b418e090017f6b0cc2","time":1772273114000,"email":"latolukasz@gmail.com","author":"Lukasz Lato","message":"New ORM"},{"hash":"bfc685f185295c4935fe51069bacb3c93ec9beda","time":1764664948000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"543b75a617cfdd17e7cf88ab1b077d0d76abe156","time":1763554211000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"2c88845a3c9e15a182e098d96677a1dc845d243a","time":1762270602000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"989d4c2ad31c7160dc4f2439beb55443c7e72b30","time":1762270480000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"},{"hash":"3e0d22a079ad480286919d95dcff3137e4fa5f4c","time":1762264658000,"email":"latolukasz@gmail.com","author":"lukaszlato","message":"Context Cache"}]},"filePathRelative":"guide/dirty_streams.md"}');export{c as comp,r as data};
